<template>
  <div class="lister">
    <h2 class="lister__title">{{ listData.title }}</h2>
    <div class="lister__container" role="list">
      <article
        class="lister__item"
        v-for="(item, index) in listData.data"
        :key="index"
        role="listitem"
      >
        <h3 class="lister__item__title">{{ item.title }}</h3>
        <p v-if="!item.type" class="lister__item__description">{{
          item.description
        }}</p>
        <time v-if="item.experience" class="lister__item__experience" datetime="">
          {{ item.experience }}
        </time>
        <a
          v-if="item.type === 'email'"
          :href="'mailto:' + item.description"
          target="_blank"
          rel="noopener noreferrer"
          class="lister__item__description lister__item__description--link"
          aria-label="Email contact"
        >
          {{ item.description }}
        </a>
        <a
          v-if="item.type === 'phone'"
          :href="'tel:' + item.description"
          target="_blank"
          rel="noopener noreferrer"
          class="lister__item__description lister__item__description--link"
          aria-label="Phone contact"
        >
          {{ item.description }}
        </a>
        <a
          v-if="item.type === 'url'"
          :href="item.description"
          target="_blank"
          rel="noopener noreferrer"
          class="lister__item__description lister__item__description--link"
          aria-label="External link"
          >{{ item.description }}</a
        >
      </article>
    </div>
  </div>
</template>

<script lang="ts">
export interface generalListInterface {
  title: string;
  data: listDataInterface[];
}

export interface listDataInterface {
  title: string;
  description: string;
  experience?: string;
  type?: "url" | "phone" | "email";
}
import { defineComponent, PropType } from "vue";

export default defineComponent({
  props: {
    isSpanish: {
      type: Boolean,
      required: true,
    },
    listData: {
      type: Object as PropType<generalListInterface>,
      required: true,
    },
  },
  data() {
    return {};
  },
});
</script>
